// ================== CONFIG ==================
const TOKEN      = 'u56B-DblvPhJ4oJ9FzgI1EGYri7v0MpCAd0etWo5_n8';
const TYPEBOT_ID = 'eyaq8oic1wo9lll5lwn5rpst';
const WEBHOOK    = 'https://sprinthub-api-master.sprinthub.app/api/hook/typebot-abandonado?i=arck1pro&access_token=1cBugHE1Ou1uljegI_4UwtS3pQU2tl9MR7bKiQ16YUIuWYNMaj';
const WINDOW_MIN = 15;   // ultimos 15 minutos
const GRACE_MIN  = 5;    // criado ha mais de 5 min
// ===========================================

const now = Date.now();

// memoria interna do n8n (guarda os ids ja disparados p/ nao repetir)
const store = $getWorkflowStaticData('global');
store.enviados = store.enviados || [];
const jaEnviado = new Set(store.enviados);

// 1) Consulta os results no Typebot
const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: `https://app.typebot.io/api/v1/typebots/${TYPEBOT_ID}/results?limit=50`,
  headers: { Authorization: `Bearer ${TOKEN}` },
  json: true,
});
const results = resp.results || [];

// helper: pega o 1o valor nao-vazio entre varios nomes de variavel possiveis
function pick(v, keys) {
  for (const k of keys) {
    if (v[k] != null && String(v[k]).trim() !== '') return String(v[k]).trim();
  }
  return '';
}

// 2) Filtra os abandonos e 3) dispara o webhook um por um (sem repetir)
const enviados = [];
const erros = [];
for (const r of results) {
  const ageMin = (now - new Date(r.createdAt).getTime()) / 60000;
  if (ageMin > WINDOW_MIN) continue;   // fora dos ultimos 15 min
  if (ageMin < GRACE_MIN)  continue;   // criado ha menos de 5 min, ainda pode estar respondendo
  if (r.isCompleted)       continue;   // completou -> nao e abandono
  if (jaEnviado.has(r.id)) continue;   // ja disparei esse lead -> pula (dedup)

  const v = {};
  for (const x of (r.variables || [])) v[x.name] = x.value;

  const telefone = String(pick(v, ['whatsapp', 'Whatsapp', 'telefone', 'phone'])).replace(/\D/g, '');
  if (!telefone) continue;             // sem contato -> nao adianta criar lead

  // nome pode vir com nomes de variavel diferentes; em abandono costuma faltar
  let nome = pick(v, ['nome', 'Nome', 'firstname', 'name', 'primeiro_nome', 'first_name']);
  if (!nome) {
    // fallback: SprintHub exige firstname nao-vazio. Usa os ultimos 4 digitos do whatsapp.
    nome = `Lead ${telefone.slice(-4)}`;
  }

  // dispara pro SprintHub -> params = slugs dos campos do CRM
  try {
    await this.helpers.httpRequest({
      method: 'POST',
      url: WEBHOOK,
      qs: {
        firstname:                 nome,              // <- nome
        whatsapp:                  telefone,          // <- whatsapp
        profissao:                 pick(v, ['profissao']),
        qual_o_valor_inicial_do_s: pick(v, ['valor']),        // <- valor
        o_que_mais_importa_nos_se: pick(v, ['atencao']),      // <- atencao
        o_que_voce_nao_gosta_nos:  pick(v, ['desconforto']),  // <- desconforto
        voce_ja_investe_em_alguma: pick(v, ['investe']),      // <- investe   (CONFIRMAR slug)
        por_que_voce_acredita_que: pick(v, ['sentido']),      // <- sentido   (CONFIRMAR slug)
        projecao_para_o_investime: pick(v, ['tempo']),        // <- tempo     (CONFIRMAR slug)
        resumo_sdr_obrigatoria:    pick(v, ['prioridade']),   // <- prioridade (CONFIRMAR slug)
        utm_content:               pick(v, ['utm_ad']),       // <- utm_ad    (CONFIRMAR slug)
      },
      json: true,
    });

    // deu certo -> marca como enviado p/ nunca repetir
    jaEnviado.add(r.id);
    store.enviados.push(r.id);
    const criadoSP = new Date(r.createdAt).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
    enviados.push({ nome, whatsapp: telefone, criado_sp: criadoSP });
  } catch (e) {
    // NAO marca como enviado -> tenta de novo na proxima execucao.
    // Tambem NAO interrompe o loop -> os demais leads continuam sendo processados.
    const detalhe = (e && e.response && e.response.body) ? e.response.body : (e && e.message) || String(e);
    erros.push({ id: r.id, nome, whatsapp: telefone, erro: detalhe });
  }
}

// mantem a memoria enxuta (guarda so os ultimos 500 ids)
if (store.enviados.length > 500) store.enviados = store.enviados.slice(-500);

// ===== OUTPUT legivel =====
const horarioExecucaoSP = new Date(now).toLocaleString('pt-BR', { timeZone: 'America/Sao_Paulo' });
const total = enviados.length;

if (total === 0 && erros.length === 0) {
  return [{ json: { execucao_sp: horarioExecucaoSP, total_enviados: 0, info: 'nenhum abandono novo neste horario' } }];
}

const out = enviados.map((e, i) => ({
  json: {
    ordem: i + 1,
    status: 'ENVIADO',
    nome: e.nome,
    whatsapp: e.whatsapp,
    criado_sp: e.criado_sp,
    total_enviados: total,
    total_erros: erros.length,
    execucao_sp: horarioExecucaoSP,
  },
}));

for (const er of erros) {
  out.push({
    json: {
      status: 'ERRO',
      nome: er.nome,
      whatsapp: er.whatsapp,
      erro: er.erro,
      total_enviados: total,
      total_erros: erros.length,
      execucao_sp: horarioExecucaoSP,
    },
  });
}

return out;
